const data = $('Message a model').first().json.message;
const content = data.content;

function extractXmlUrls(inputData) {
  // Declare xmlUrls as an array and provide a JSDoc type hint for better type inference.
  /** @type {string[]} */
  const xmlUrls = [];

  // Helper function to recursively traverse an object or array
  function traverse(data) {
    if (Array.isArray(data)) {
      data.forEach(item => traverse(item));
    } else if (typeof data === 'object' && data !== null) {
      for (const key in data) {
        if (Object.prototype.hasOwnProperty.call(data, key)) {
          traverse(data[key]);
        }
      }
    } else if (typeof data === 'string') {
      // Updated regex to specifically extract direct URLs ending with .xml
      // This will match "https://lgp.org.au/wp-sitemap-posts-post-1.xml" directly.
      const urlMatch = data.match(/(https:\/\/[^\s]+\.xml)/);
      if (urlMatch && urlMatch[1]) { // Check if a match was found and the capturing group exists
        xmlUrls.push(urlMatch[1]); // Push the captured URL
      }
    }
  }

  traverse(inputData); // Start traversal with the provided input data
  return xmlUrls;
}

// Your input variables from the environment
