let parsedContent = {};
try {
  // Use the 'content' variable directly as provided by your input.
  const jsonMatch = content.match(/```json\n([\s\S]*?)\n```/);
  if (jsonMatch && jsonMatch[1]) {
    parsedContent = JSON.parse(jsonMatch[1]);
  } else {
    console.log("Could not find JSON content within markdown block.");
  }
} catch (e) {
  console.log("Error parsing content:", e);
}

// Extract the XML URLs from the *parsed* content
// The extractXmlUrls function is now called with the parsed JSON object.
const extractedUrls = extractXmlUrls(parsedContent);

// Log the extracted URLs to the console (for debugging within your environment)
console.log("Extracted XML URLs:");
extractedUrls.forEach(url => console.log(url));

// Return the extracted URLs in a format expected by many environments (e.g., n8n's Code node)
// This transforms the array of strings into an array of objects, where each object
// represents an 'item' with a 'url' property.
return extractedUrls.map(url => ({ url: url }));

function extractAllLocs(data) {
    const locs = [];

    function findLocs(obj) {
        if (!obj) return;

        // If it's an object, check for loc key and continue recursion
        if (typeof obj === 'object') {
            for (const key in obj) {
                if (key === 'loc' && typeof obj[key] === 'string') {
                    locs.push(obj[key]);
                } else {
                    findLocs(obj[key]);
                }
            }
        }
        // If it's an array, loop through each item
        else if (Array.isArray(obj)) {
            obj.forEach(findLocs);
        }
    }

    findLocs(data);
    return locs.map(url => ({ url }));
}

