// --- This Code Node extracts 'content' from nested documents ---

// Step 1: Safely access the nested 'documents' array from the input.
// This code will try to find the 'documents' array in several common locations
// within the n8n input data structure to ensure it's found regardless of
// how the previous node is configured.
const inputData = $input.all()[0];
let documents = null;

if (inputData?.documents && Array.isArray(inputData.documents)) {
  documents = inputData.documents;
} else if (inputData?.json?.documents && Array.isArray(inputData.json.documents)) {
  documents = inputData.json.documents;
} else if (inputData?.output?.documents && Array.isArray(inputData.output.documents)) {
  documents = inputData.output.documents;
}

// Step 2: Check if the documents array was found before proceeding.
if (!documents || !Array.isArray(documents)) {
  console.log("No documents array found in the input. Returning an empty string.");
  return [{ json: { validContent: "" } }];
}

// Step 3: Use .map() to iterate over the 'documents' array.
// For each document, access its 'content' property.
const contentArray = documents.map(document => {
  // Basic safety check: ensure document.content exists.
  // Return null if not found, otherwise return the content.
  return document.content ?? null;
});

// Log the result of Step 3 to see the raw array with potential null values
console.log("Content Array (after mapping):", contentArray);

// Step 4: Filter out any potential null values if an item
// was missing content (optional)
const validContentArray = contentArray.filter(content =>
  content !== null
);

// Log the result of Step 4 to see the cleaned array
console.log("Valid Content Array (after filtering):", validContentArray);

// Step 5: Join the array of valid content into a single string.
// We use a newline as a separator to keep the content readable.
const validContentString = validContentArray.join('\n\n');

// Log the final single string
console.log("Final Combined Content String:", validContentString);

// Step 6: Return the final string in the expected n8n format.
return [{ json: { validContent: validContentString } }];

