const documents = $('RAG-CAHT_SUPABASE1').first().json.documents;
const outputData = $('RAG-CAHT_SUPABASE1').first().json.output;

// Sort the documents by final_score in descending order.
documents.sort((a, b) => b.final_score - a.final_score);

// Get the top two documents.
const topTwoDocuments = documents.slice(0, 2);

// Extract the content from the top two documents and join them into a single string.
const combinedContent = topTwoDocuments.map(doc => doc.content).join(' ... ');

// Return the outputData and the combined content together.
return [
  {
    json: {
      outputData: outputData,
      combinedContent: combinedContent
    }
  }
];
